import{_ as e,o,c as n,ag as s}from"./chunks/framework.ePeAWSvT.js";const r="/assets/build-connectors.Cj8PDgu1.png",i="/assets/modal-connector-add.CAsK695I.png",a="/assets/modal-connector-edit.KCtMDjVr.png",c="/assets/modal-connector-connect.CR4CZa7F.png",l="/assets/modal-connector-test.CGqfHzWn.png",C=JSON.parse('{"title":"Connectors","description":"","frontmatter":{},"headers":[],"relativePath":"guide/build-connectors.md","filePath":"guide/build-connectors.md"}'),d={name:"guide/build-connectors.md"};function p(g,t,h,u,m,f){return o(),n("div",null,[...t[0]||(t[0]=[s('<h1 id="connectors" tabindex="-1">Connectors <a class="header-anchor" href="#connectors" aria-label="Permalink to &quot;Connectors&quot;">​</a></h1><p>Connectors give Central the necessary security settings to interact with specific software systems such as Dynamics 365 or Salesforce. You&#39;ll need to designate both a method and a protocol for each Connector. A method is how the <a href="./reference-common-model.html">Common Model</a> interacts with the connected system (e.g. Get, Put). A protocol is the data format that the API supports (e.g. JSON, SQL, XML).</p><p><img src="'+r+'" alt="Connectors Page"></p><h2 id="key-features" tabindex="-1">Key Features <a class="header-anchor" href="#key-features" aria-label="Permalink to &quot;Key Features&quot;">​</a></h2><ul><li><strong>Multiple System Support</strong> — Connect to REST APIs, SQL databases, SFTP servers, Azure Blob Storage, and more</li><li><strong>Authentication Types</strong> — Support for OAuth, API Key, Basic Auth, and custom authentication</li><li><strong>Secure Storage</strong> — Credentials and secrets are stored securely and never exposed in the UI</li><li><strong>Company Scoping</strong> — Associate connectors with specific companies for multi-tenant setups</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Since connectivity is pre-built in Central, there is no need to use Postman. Simply use the Test Connector to write test requests and check responses.</p></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Have the authentication information from each vendor associated with the connections you plan to implement before starting. For links to common vendor documentation, see the <a href="./reference-connectors.html">Connectors Catalog</a>.</p></div><h2 id="add-a-new-connector" tabindex="-1">Add a New Connector <a class="header-anchor" href="#add-a-new-connector" aria-label="Permalink to &quot;Add a New Connector&quot;">​</a></h2><p><img src="'+i+'" alt="Add Connector Modal"></p><ol><li><p>Select <strong>Build</strong> &gt; <strong>Connectors</strong> from the main menu.</p></li><li><p>Select <strong>+ Add</strong>.</p></li><li><p>Select a <strong>Connector</strong> from the list.</p></li><li><p>Select <strong>Next</strong>.</p></li><li><p>As needed, enter a new <strong>Name</strong> for the Connector.</p></li><li><p>Enter the <strong>Secure Settings</strong> information.</p></li></ol><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>The data entered for all Secure Setting fields must match your system&#39;s specific security details. This information can typically be found in the Admin settings of the system you are trying to connect.</p></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Secure setting fields will vary by Connector. To view entered data, toggle the <strong>View</strong>/<strong>Hide</strong> icon in each entry field, or select <strong>Hide All</strong> or <strong>View All</strong>.</p></div><ol start="7"><li>Select <strong>Save</strong>. The Connector will now appear on the Manage Connectors screen.</li></ol><h2 id="edit-a-connector" tabindex="-1">Edit a Connector <a class="header-anchor" href="#edit-a-connector" aria-label="Permalink to &quot;Edit a Connector&quot;">​</a></h2><ol><li><p>Select <strong>Build</strong> &gt; <strong>Connectors</strong> from the main menu.</p></li><li><p>Select <strong>Actions</strong> &gt; <strong>Edit</strong> in the appropriate Connector card.</p></li></ol><p><img src="'+a+'" alt="Edit Connector Modal"></p><ol start="3"><li>Modify the Connector <strong>Name</strong> and/or <strong>Secure Settings</strong>.</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>To discard all changes and start over, select <strong>Reset</strong>. To discard all changes and exit edit mode, select <strong>Cancel</strong>.</p></div><ol start="4"><li>Select <strong>Save</strong>.</li></ol><h2 id="additional-instructions" tabindex="-1">Additional Instructions <a class="header-anchor" href="#additional-instructions" aria-label="Permalink to &quot;Additional Instructions&quot;">​</a></h2><p>The <strong>Instructions</strong> tab on the Edit Connector dialog lets you add request instructions that apply to <strong>every</strong> outgoing call this connector makes — useful for setting custom HTTP headers, query parameters, or time-zone conversion of the LastRun timestamp without modifying every endpoint individually.</p><ol><li><p>Select <strong>Build</strong> &gt; <strong>Connectors</strong> from the main menu.</p></li><li><p>Select <strong>Actions</strong> &gt; <strong>Edit</strong> in the appropriate Connector card.</p></li><li><p>Switch to the <strong>Instructions</strong> tab.</p></li><li><p>Select <strong>+ Add Instruction</strong> and choose an instruction type:</p><ul><li><strong>Header / String Value</strong> — set an HTTP header, query parameter, or body field. Choose a <strong>Target</strong>, then enter a <strong>Key</strong> and <strong>Value</strong> (e.g. <code>Header</code> / <code>Accept-Language</code> / <code>en-US</code>).</li><li><strong>Time Zone Conversion</strong> — shift the LastRun timestamp into a chosen IANA time zone (e.g. <code>America/New_York</code>) before it gets injected into parameters such as <code>{SYS:DateLastPolled}</code>. See <a href="./datahub-endpoint-config.html#time-zone-conversion">Time Zone Conversion</a> for details on when to use this.</li></ul></li><li><p>Select <strong>Save</strong> in the dialog, then <strong>Save</strong> on the connector.</p></li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>A common use case is forcing a culture or region header on every request. For per-endpoint overrides (e.g. a different <code>Prefer</code> value on a specific Read), use <a href="./datahub-endpoint-config.html#additional-instructions">Additional Instructions on the endpoint action</a> instead.</p></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>If the same header name (e.g. <code>Prefer</code>) is set both at the connector level and on a specific endpoint action, <strong>the endpoint-level value replaces the connector-level value entirely</strong> for that endpoint — including any other values for the same header. If you need to keep a connector-wide preference alongside an endpoint override, restate it explicitly on the endpoint.</p></div><h2 id="copy-webhook-url" tabindex="-1">Copy Webhook URL <a class="header-anchor" href="#copy-webhook-url" aria-label="Permalink to &quot;Copy Webhook URL&quot;">​</a></h2><p>For webhook-enabled connectors, you can copy the webhook URL directly from the connector card.</p><ol><li><p>Select <strong>Build</strong> &gt; <strong>Connectors</strong> from the main menu.</p></li><li><p>In the appropriate Connector, select <strong>Actions</strong> &gt; <strong>Copy Webhook URL</strong>.</p></li><li><p>The webhook URL is copied to your clipboard. A success notification will confirm.</p></li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>The Copy Webhook URL action only appears for connectors that support webhooks (e.g. Shopify, HubSpot). If your connector does not support webhooks, this option will not be visible.</p></div><h2 id="delete-a-connector" tabindex="-1">Delete a Connector <a class="header-anchor" href="#delete-a-connector" aria-label="Permalink to &quot;Delete a Connector&quot;">​</a></h2><ol><li><p>Select <strong>Build</strong> &gt; <strong>Connectors</strong> from the main menu.</p></li><li><p>Select <strong>Actions</strong> &gt; <strong>Delete</strong> in the appropriate Connector card.</p></li><li><p>Select <strong>OK</strong> to confirm the deletion.</p></li></ol><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Deleting a Connector cannot be undone; you must recreate it if needed.</p></div><h2 id="connect-a-connector" tabindex="-1">Connect a Connector <a class="header-anchor" href="#connect-a-connector" aria-label="Permalink to &quot;Connect a Connector&quot;">​</a></h2><p><img src="'+c+'" alt="Connect Connector Dialog"></p><ol><li><p>Select <strong>Build</strong> &gt; <strong>Connectors</strong> from the main menu.</p></li><li><p>In the appropriate Connector, select <strong>Actions</strong> &gt; <strong>Connect</strong>.</p></li><li><p>The <strong>Test Connection</strong> window will appear. The system will attempt to connect to ensure the secure settings are operational; once successful, the connection details will be displayed.</p></li></ol><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>If an error occurs while trying to connect, a pop-up notification will disclose details as to why the connection failed. Select the <strong>X</strong> to close the error window.</p></div><ol start="4"><li>When finished, select <strong>Cancel</strong> to return to the Manage Connectors screen.</li></ol><h2 id="test-a-connector" tabindex="-1">Test a Connector <a class="header-anchor" href="#test-a-connector" aria-label="Permalink to &quot;Test a Connector&quot;">​</a></h2><p><img src="'+l+'" alt="Test Connector Dialog"></p><ol><li><p>Select <strong>Build</strong> &gt; <strong>Connectors</strong> from the main menu.</p></li><li><p>In the appropriate Connector, select <strong>Actions</strong> &gt; <strong>Test</strong>.</p></li><li><p>Select a <strong>Method</strong> (e.g. GET, PUT, POST, DELETE).</p></li><li><p>Select a <strong>Protocol</strong> (e.g. JSON, XML, SQL).</p></li><li><p>Enter <strong>Route</strong> data (the API endpoint path).</p></li><li><p>Select <strong>Send</strong>.</p></li><li><p>The request will display on the <strong>Body</strong> tab; the response will display on the <strong>Response</strong> tab.</p></li><li><p>Select <strong>Close</strong> to exit the test window.</p></li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>If needed, click on <strong>Headers</strong> to enter additional HTTP Header values or Key values for the request.</p></div>',40)])])}const y=e(d,[["render",p]]);export{C as __pageData,y as default};
